What does this program print?

```cpp
#include <iostream>
#include <stdexcept>
class D : public std::runtime_error {
public:
    D() : std::runtime_error("d") {}
};
int main() {
    try {
        try { throw D(); }
        catch (const std::runtime_error& e) {
            throw; // bare rethrow
        }
    } catch (const D& d) {
        std::cout << "D\n";
    } catch (const std::runtime_error&) {
        std::cout << "runtime\n";
    }
    return 0;
}
```

